import 'package:flutter/services.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

final LocalAuthentication auth = LocalAuthentication();

Future<void> authenticate() async {
  bool canCheckBiometrics;
  List<BiometricType> availableBiometrics;

  try {
    canCheckBiometrics = await auth.canCheckBiometrics;
    availableBiometrics = await auth.getAvailableBiometrics();
  } on PlatformException catch (e) {
    print(e);
    return; // Handle exception and show password input instead
  }

  if (!canCheckBiometrics) {
    print('Device does not support biometric authentication.');
    return; // Show password input instead
  }

  try {
    bool authenticated = await auth.authenticateWithBiometrics(
      localizedReason: 'Authenticate with biometrics to access the app',
      useFingerprint: canCheckBiometricTypes(availableBiometrics, BiometricType.fingerprint),
      useFaceId: canCheckBiometricTypes(availableBiometrics, BiometricType.faceId),
    );

    if (authenticated) {
      await SharedPreferences.getInstance().setBool('authenticated', true);
    }
  } on PlatformException catch (e) {
    print(e);
  }
}

bool canCheckBiometricTypes(List<BiometricType> available, BiometricType type) {
  return available.contains(type);
}